mapper.select:
select sapt.id as rowId ,puser.name as userName, csci.name as committeeName,sapt.branch as branch, csy.name as yearName,sdept.name as deptName,suser.name as subUserName, sapt.sub_date as subDate, cspj.name as positionName, cspt.name as partTimeTypeName, sapt.start_date as startDate,sapt.end_date as endDate,sapt.data_status as dataStatus from srm_ac_parttime_apply sapt left join ct_srm_user puser on puser.id=sapt.user_id left join ct_srm_committee_info csci on csci.code=sapt.committee left join ct_srm_year csy on csy.code=sapt.year left join ct_srm_parttime_job cspj on cspj.code=sapt.position left join ct_srm_parttime_type cspt on cspt.code=sapt.part_time_type left join ct_srm_dept sdept on sdept.id=sapt.dept_id left join ct_srm_user suser on suser.id=sapt.sub_user_id where (sapt.sub_user_id=#{acParttimeApplyDto.userId} or sapt.create_user_id=#{acParttimeApplyDto.userId} )
and sapt.data_status = #{acParttimeApplyDto.dataStatus}
and sapt.committee = #{acParttimeApplyDto.committee}
and sapt.branch LIKE CONCAT('%', #{acParttimeApplyDto.branch}, '%')
and sapt.year = #{acParttimeApplyDto.year}
and sapt.part_time_type = #{acConferenceHostDto.partTimeType}
and sapt.sub_date >= #{acParttimeApplyDto.startDate}
and sapt.sub_date <= #{acParttimeApplyDto.endDate}

select sapt.id as rowId ,puser.name as userName, csci.name as committeeName,sapt.committee_branch as committeeBranch,sapt.committee_branch as committeeBranch, csy.name as yearName,sdept.name as deptName,suser.name as subUserName, sapt.sub_date as subDate,sapt.branch as branch, cspj.name as positionName, cspt.name as partTimeTypeName, sapt.start_date as startDate,sapt.end_date as endDate,sapt.data_status as dataStatus from srm_ac_parttime_apply sapt left join ct_srm_user puser on puser.id=sapt.user_id left join ct_srm_committee_info csci on csci.code=sapt.committee left join ct_srm_year csy on csy.code=sapt.year left join ct_srm_parttime_job cspj on cspj.code=sapt.position left join ct_srm_parttime_type cspt on cspt.code=sapt.part_time_type left join ct_srm_dept sdept on sdept.id=sapt.dept_id left join ct_srm_user suser on suser.id=sapt.sub_user_id left join cf_srm_eaf_rec eafrec on eafrec.sys_no="P051" and eafrec.check_rec_id=sapt.id where eafrec.step_no>1
and sapt.committee = #{acParttimeApplyDto.committee}
and sapt.branch LIKE CONCAT('%', #{acParttimeApplyDto.branch}, '%')
and sapt.year = #{acParttimeApplyDto.year}
and sapt.part_time_type = #{acConferenceHostDto.partTimeType}
and sapt.sub_date >= #{acParttimeApplyDto.startDate}
and sapt.sub_date <= #{acParttimeApplyDto.endDate}
and ( (sapt.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{acParttimeApplyDto.userId}, '|%')) or (eafrec.step_no = (select max(step_no) from cf_srm_eaf_rec seafrec where seafrec.sys_no="P051" and seafrec.check_rec_id=sapt.id) and eafrec.checker_string LIKE CONCAT('%|', #{acParttimeApplyDto.userId}, '|%') and eafrec.check_datetime is not null) or (sapt.data_status=0 and eafrec.is_current_step=1 and eafrec.check_result=3 and eafrec.checker_string LIKE CONCAT('%|', #{acParttimeApplyDto.userId}, '|%')) )
and sapt.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{acParttimeApplyDto.userId}, '|%')
and sapt.data_status=1 and eafrec.check_result="2" and eafrec.checker_string LIKE CONCAT('%|', #{acParttimeApplyDto.userId}, '|%')
and sapt.data_status=0 and eafrec.check_result="3" and eafrec.checker_string LIKE CONCAT('%|', #{acParttimeApplyDto.userId}, '|%')
